-- citizens database — mock government registry
-- 100 Kenyan + 100 Trinidad & Tobago citizens
-- Powers the data source layer for the v1 demo.

DROP TABLE IF EXISTS citizens;

CREATE TABLE citizens (
  id SERIAL PRIMARY KEY,
  national_id VARCHAR(30) UNIQUE NOT NULL,
  country_code CHAR(2) NOT NULL,
  first_name VARCHAR(100) NOT NULL,
  middle_name VARCHAR(100),
  last_name VARCHAR(100) NOT NULL,
  gender VARCHAR(10),
  date_of_birth DATE NOT NULL,
  place_of_birth VARCHAR(200),
  nationality VARCHAR(50),
  address TEXT,
  phone VARCHAR(30),
  email VARCHAR(150),
  -- Birth certificate
  birth_registration_number VARCHAR(50) UNIQUE NOT NULL,
  birth_registration_date DATE NOT NULL,
  mother_name VARCHAR(200),
  father_name VARCHAR(200),
  -- University degree (nullable)
  university VARCHAR(200),
  degree_type VARCHAR(50),
  major VARCHAR(150),
  graduation_date DATE,
  gpa DECIMAL(3,2),
  student_id VARCHAR(50),
  -- Farmer ID (nullable)
  farm_id VARCHAR(30),
  farm_location VARCHAR(300),
  farm_size_hectares DECIMAL(10,2),
  primary_crops VARCHAR(500),
  farm_registration_date DATE
);

CREATE INDEX idx_citizens_national_id ON citizens(national_id);
CREATE INDEX idx_citizens_country ON citizens(country_code);
CREATE INDEX idx_citizens_has_university ON citizens(country_code) WHERE university IS NOT NULL;
CREATE INDEX idx_citizens_has_farm ON citizens(country_code) WHERE farm_id IS NOT NULL;

