SELECT COUNT(*) AS total_citizens FROM citizens;
SELECT country_code, COUNT(*) AS count FROM citizens GROUP BY country_code;
SELECT COUNT(*) AS with_university FROM citizens WHERE university IS NOT NULL;
SELECT COUNT(*) AS with_farm FROM citizens WHERE farm_id IS NOT NULL;
SELECT COUNT(*) AS with_both FROM citizens WHERE university IS NOT NULL AND farm_id IS NOT NULL;
